const SCENARIOS={flood:[{id:"fl_01",title:"洪水警报",setting:"🏠 家里",icon:"🌊",desc:"你正坐在家里看电视，突然窗外响起急促的警报声，📱手机收到气象局的洪水预警：短时强降雨导致河水暴涨，预计30分钟后漫堤！",choices:[{text:"立即带上必需品向高地转移",correct:!0,response:"✅ 正确！收到预警后应立即转移到高地或安全区域！",score:10},{text:"待在家里关好门窗就没事",correct:!1,response:"❌ 洪水可能淹没低洼地区，待在家里非常危险！",score:0},{text:"下楼去河边看看水位",correct:!1,response:"❌ 靠近河边极易被突涨的洪水卷走，绝对不要！",score:0}],effect:"flood_warn",tip:"收到洪水预警后，立即向高地转移！"},{id:"fl_02",title:"洪水围城",setting:"🏠 家中二楼",icon:"🌊",desc:"水位已经涨到一楼窗台，你被困在二楼。水还在继续上涨，你听到楼下传来家具漂浮撞击的声音...",choices:[{text:"上屋顶等待救援",correct:!0,response:"✅ 正确！洪水淹没房屋时，应往高处（屋顶）撤离等待救援！",score:10},{text:"游泳游出去",correct:!1,response:"❌ 洪水中夹杂大量杂物和暗流，游泳极易被冲走或撞伤！",score:0},{text:"躲到地下室去",correct:!1,response:"❌ 地下室是洪水时最危险的地方！水会灌入且没有逃生出口！",score:0}],effect:"flood_rise",tip:"洪水进屋时，向上走！屋顶是最后的避难所。"},{id:"fl_03",title:"等待救援",setting:"🏠 屋顶上",icon:"🌊",desc:"你爬上了屋顶，远处有救援队的冲锋舟在搜救。天色渐暗，水位还在缓慢上涨，你必须引起他们的注意！",choices:[{text:"挥动鲜艳的衣物或手电筒发信号",correct:!0,response:"✅ 正确！鲜艳颜色和灯光在搜救时最容易被发现！",score:10},{text:"跳下水游向救援船",correct:!1,response:"❌ 洪水暗流多，跳入水中非常危险，应待在屋顶等待救援船靠近！",score:0},{text:"大声喊叫直到嗓子哑",correct:!1,response:"❌ 可以喊叫但不要耗尽体力，用鲜艳物品发信号更有效！",score:5}],effect:"flood_rescue",tip:"被洪水围困时，用鲜艳物品发信号比喊叫更有效！"}],earthquake:[{id:"eq_01",title:"教室地震",setting:"🏫 教室里",icon:"🌍",desc:"你正在教室里上课，突然地板剧烈晃动，灯管摇摆不停，窗户外传来轰隆隆的响声！地震了！",choices:[{text:"立即钻到课桌下，抱头蹲好",correct:!0,response:"✅ 正确！伏地、遮挡、手抓牢——桌椅三角区是最安全的位置！",score:10},{text:"尖叫着跑出教室",correct:!1,response:"❌ 地震时跑动极易被掉落物砸伤！应先躲避，等震感减弱再撤离！",score:0},{text:"跳窗逃生",correct:!1,response:"❌ 跳窗可能导致骨折或更严重的伤害！教室在楼上更危险！",score:0}],effect:"shake",tip:"地震时牢记：伏地、遮挡、手抓牢！"},{id:"eq_02",title:"震后处理",setting:"🏠 家里",icon:"🌍",desc:"地震结束了，你从桌子下爬出来。家里一片狼藉，空气中弥漫着灰尘和煤气味...",choices:[{text:"关闭燃气阀门和电闸，然后离开",correct:!0,response:"✅ 正确！震后首要任务是切断燃气和电源，防止火灾和爆炸！",score:10},{text:"点根蜡烛照亮看看情况",correct:!1,response:"❌ 有煤气味时点火可能引发爆炸！应用手电筒照明！",score:0},{text:"坐电梯下楼",correct:!1,response:"❌ 震后电梯可能损坏或断电被困！必须走楼梯！",score:0}],effect:"dark",tip:"震后先关燃气和电闸，走楼梯撤离，不要用明火！"},{id:"eq_03",title:"户外避震",setting:"🏞️ 街道上",icon:"🌍",desc:"你正在街上走路，突然地面晃动起来。周围的高楼玻璃哗哗作响，行人惊慌失措...",choices:[{text:"跑到开阔的空地或广场",correct:!0,response:"✅ 正确！户外避震应远离建筑物、路灯和电线杆，到开阔地带！",score:10},{text:"站在高楼旁边躲着",correct:!1,response:"❌ 高楼可能掉落玻璃和砖块，站在旁边非常危险！",score:0},{text:"躲进路边的桥洞",correct:!1,response:"❌ 桥洞在地震时可能坍塌！应选择开阔无遮挡的区域！",score:0}],effect:"shake",tip:"户外避震远离建筑物，去开阔地！"}],typhoon:[{id:"ty_01",title:"台风来临",setting:"🏠 家里",icon:"🌪️",desc:"气象台发布了台风红色预警：超强台风「海神」将在6小时后登陆，中心风力达17级！窗外风声渐起...",choices:[{text:'加固门窗，用胶带贴"米"字，储备物资',correct:!0,response:"✅ 正确！台风前加固门窗、储备食物和水是最重要的准备工作！",score:10},{text:"趁台风还没来赶紧出门买东西",correct:!1,response:"❌ 台风来临前应避免外出！应提前储备好物资待在家里！",score:0},{text:"去海边看巨浪",correct:!1,response:"❌ 台风天去海边极度危险！巨浪可能把人卷入海中！",score:0}],effect:"wind",tip:"台风来临前：加固门窗、储备物资、不要外出！"},{id:"ty_02",title:"台风过境",setting:"🏠 家中",icon:"🌪️",desc:"台风正在肆虐，狂风呼啸，暴雨如注。突然停电了，四周一片漆黑，你该怎么办？",choices:[{text:"用手电筒或应急灯照明",correct:!0,response:"✅ 正确！台风天停电应用手电筒照明，备好备用电池！",score:10},{text:"点蜡烛或煤油灯",correct:!1,response:"❌ 台风天可能造成燃气泄漏，明火非常危险！应用手电筒！",score:0},{text:"打开窗户看看外面情况",correct:!1,response:"❌ 台风天开窗会让强风灌入，可能导致屋顶被掀翻！",score:0}],effect:"wind",tip:"台风天停电用手电筒，不要用明火！紧闭门窗！"},{id:"ty_03",title:"台风过后",setting:"🏘️ 社区",icon:"🌪️",desc:"台风过去了，外面一片狼藉：倒下的树木、积水的街道、破损的房屋...你想出去看看情况。",choices:[{text:"检查房屋受损情况，注意避开倒下的电线",correct:!0,response:"✅ 正确！台风后检查房屋时注意安全，尤其要远离断落的电线！",score:10},{text:"立刻出门到处逛",correct:!1,response:"❌ 台风后路面可能有倒塌物和漏电电线，应小心谨慎！",score:0},{text:"喝自来水解渴",correct:!1,response:"❌ 台风后自来水可能被污染，应喝储备的瓶装水或烧开后再喝！",score:0}],effect:"flood_warn",tip:"台风后注意：远离电线、喝瓶装水、小心出行！"}],landslide:[{id:"ls_01",title:"山体异动",setting:"🏔️ 山脚下",icon:"⛰️",desc:"连日暴雨后，你发现屋后的山坡上出现了裂缝，偶尔有小石块滚落下来，地面似乎在微微移动...",choices:[{text:"立即向垂直于滑坡方向的两侧高处跑",correct:!0,response:"✅ 正确！向滑坡方向的两侧跑是唯一的逃生方向！",score:10},{text:"向上跑到山顶",correct:!1,response:"❌ 向上跑可能正好进入滑坡路径！应向两侧跑！",score:0},{text:"向下跑到山脚",correct:!1,response:"❌ 向下跑会被滑坡追上掩埋！应向两侧高处跑！",score:0}],effect:"shake",tip:"遇到滑坡征兆，千万不要顺着或逆着方向跑，要向两侧逃生！"},{id:"ls_02",title:"夜间异响",setting:"🏠 家中",icon:"⛰️",desc:"深夜，你被一阵轰隆隆的巨响惊醒，感觉房子在震动。屋后的山坡上传来了树木断裂的声音...",choices:[{text:"立即叫醒家人，向安全方向撤离",correct:!0,response:"✅ 正确！夜间听到异响应立即撤离！泥石流夜间更危险！",score:10},{text:"打开窗户看看怎么回事",correct:!1,response:"❌ 分秒必争！不应该浪费时间查看，立即撤离！",score:0},{text:"继续睡觉，可能是打雷",correct:!1,response:"❌ 山坡异响+震动是泥石流的典型前兆！立刻撤离！",score:0}],effect:"dark",tip:"夜间听到山体异响应立即撤离，不要犹豫！"}],tsunami:[{id:"ts_01",title:"海水后退",setting:"🏖️ 海滩上",icon:"🌊",desc:"你在海边玩，突然感觉到一阵地震般的晃动。紧接着，海水以惊人的速度向后退去，露出大片海底，鱼在沙滩上扑腾...",choices:[{text:"意识到海啸即将来临，立刻向高地跑",correct:!0,response:"✅ 正确！海水突然后退是海啸来临的明确信号！立即向高处跑！",score:10},{text:"趁海水退了去捡贝壳和鱼",correct:!1,response:"❌ 太危险了！海啸速度可达800km/h，几分钟内就会扑过来！",score:0},{text:"站在原地好奇地看",correct:!1,response:"❌ 这是海啸前兆！犹豫一两分钟就可能被巨浪吞没！",score:0}],effect:"shake",tip:"看到海水突然后退，不要犹豫，立刻往高处跑！"},{id:"ts_02",title:"海啸预警",setting:"🏠 海边小镇",icon:"🌊",desc:"地震发生后5分钟，手机收到海啸预警：预计20分钟后10米高的巨浪将袭击海岸。镇上的广播也在紧急疏散！",choices:[{text:"开车或跑步向海拔高的内陆撤离",correct:!0,response:"✅ 正确！收到海啸预警后应尽快向内陆和高处撤离！",score:10},{text:"先去海边看看浪来了没有",correct:!1,response:"❌ 海啸速度极快！去看一眼就可能来不及撤离！",score:0},{text:"待在家里，房子很坚固",correct:!1,response:"❌ 10米高的巨浪足以摧毁大部分建筑！必须撤离！",score:0}],effect:"flood_warn",tip:"收到海啸预警立刻撤离，不要观望！奔向高处！"},{id:"ts_03",title:"与时间赛跑",setting:"🏃 撤离路上",icon:"🌊",desc:"你正在拼命往高处跑，身后传来巨大的轰鸣声。回头一看，一道白色巨墙正在逼近——海啸来了！前方有一座坚固的钢筋混凝土高楼。",choices:[{text:"跑进高楼，上到3层以上",correct:!0,response:"✅ 正确！如果来不及到高地，坚固建筑的高层也是安全的避难所！",score:10},{text:"继续往海边方向跑",correct:!1,response:"❌ 海啸方向是冲向海岸的！往海边跑就是送死！",score:0},{text:"躲到大桥底下",correct:!1,response:"❌ 桥梁可能被海啸冲垮！应选择坚固建筑的高层！",score:0}],effect:"flood_rise",tip:"来不及到高地时，选择坚固建筑的高层避难！"}],lightning:[{id:"li_01",title:"野外雷雨",setting:"🏞️ 野外",icon:"⚡",desc:"你在户外登山，突然乌云密布，雷声滚滚。闪电就在不远处劈下来，击中了一棵大树！你周围没有建筑可以躲避。",choices:[{text:"蹲低身体，双脚并拢，减少与地面接触",correct:!0,response:"✅ 正确！打雷时蹲低、双脚并拢减少跨步电压的风险！",score:10},{text:"站到大树下躲雨",correct:!1,response:"❌ 大树是雷击的高危目标！站在树下极其危险！",score:0},{text:"趴在地上平躺",correct:!1,response:"❌ 平躺会增加与地面的接触面积，反而增加跨步电压危险！",score:0}],effect:"dark",tip:"野外遇雷电：蹲低、双脚并拢、远离大树和高地！"},{id:"li_02",title:"室内防雷",setting:"🏠 家里",icon:"⚡",desc:"外面雷雨交加，一道闪电击中了附近的变压器，家里灯光闪了闪。你正拿着手机，房间里还有电视和电脑开着。",choices:[{text:"拔掉电器插头，不要用手机和固定电话",correct:!0,response:"✅ 正确！雷电可能通过电线损坏电器，应拔掉插头！固定电话也会引雷！",score:10},{text:"继续用手机玩游戏",correct:!1,response:"❌ 虽然手机本身不引雷，但雷雨天最好不用充电中的电子设备！",score:5},{text:"去洗个热水澡",correct:!1,response:"❌ 水管是导电的！雷雨天洗澡可能触电！绝对禁止！",score:0}],effect:"dark",tip:"室内防雷：拔插头、不洗澡、不用固定电话！"}],snowstorm:[{id:"sn_01",title:"暴雪被困",setting:"🚗 车内",icon:"❄️",desc:"你开车回家，突然暴雪降临，能见度不到1米，车被堵在了高速公路上。气温急剧下降到零下20度，油箱只剩一半油。",choices:[{text:"待在车内，开暖气，每隔1小时开窗通风",correct:!0,response:"✅ 正确！暴雪中被困车内应待在车里，注意通风防止一氧化碳中毒！",score:10},{text:"下车步行寻找救援",correct:!1,response:"❌ 暴雪中能见度极低，下车步行极易迷路冻伤！待在车内更安全！",score:0},{text:"不停跑步取暖",correct:!1,response:"❌ 跑步会大量消耗体力并出汗，汗湿的衣服会导致失温更快！",score:0}],effect:"snow",tip:"暴雪被困车内：待在车里、轮流通暖风、注意通风！"},{id:"sn_02",title:"暴雪备灾",setting:"🏠 家里",icon:"❄️",desc:"天气预报说今晚会有特大暴雪，可能会持续3天。气温降至零下25度，你家暖气是电暖器。",choices:[{text:"储备食物、水、药品和备用电池",correct:!0,response:"✅ 正确！暴雪前应储备3天以上的物资和取暖设备！",score:10},{text:"趁还没下雪出门旅游",correct:!1,response:"❌ 暴雪预警意味着极端天气即将来临，外出非常危险！",score:0},{text:"打开窗户让房间通风",correct:!1,response:"❌ 暴雪前要做好保暖，开窗会让室内温度急剧下降！",score:0}],effect:"snow",tip:"暴雪前储备3天物资+保暖设备，尽量待在家里！"}],wildfire:[{id:"wf_01",title:"发现山火",setting:"🏞️ 郊外",icon:"🔥",desc:"你在郊外徒步时，闻到一股焦糊味，抬头看到远处山坡上浓烟滚滚，火光冲天——山火正在蔓延！风向正朝你这边吹来！",choices:[{text:"逆着风向撤离到已烧过的区域",correct:!0,response:"✅ 正确！逆风撤离可远离火势，已烧过的区域反而最安全！",score:10},{text:"顺风跑下山",correct:!1,response:"❌ 顺风跑会被火势追上！火势蔓延速度比人跑得快！",score:0},{text:"冲过去帮忙救火",correct:!1,response:"❌ 山火非常危险，未经训练的普通人不应试图扑救！立即撤离并报警！",score:0}],effect:"fire",tip:"遇山火：逆风撤离！到已烧过的区域最安全！"},{id:"wf_02",title:"山火逼近",setting:"🏠 家中",icon:"🔥",desc:"山火正朝你家的方向蔓延，消防员已经通知大家准备撤离。空气中弥漫着浓烟，你能看到远处的火光越来越近。",choices:[{text:"关闭门窗和燃气阀门，准备好湿毛巾和应急包",correct:!0,response:"✅ 正确！撤离前关闭门窗防火星进入，准备好防护用品！",score:10},{text:"打开所有窗户让烟散去",correct:!1,response:"❌ 开窗会让火星飘入屋内引发火灾！应紧闭门窗！",score:0},{text:"放火烧掉房子周围的东西作为防火带",correct:!1,response:"❌ 放火极度危险且违法！应由专业消防人员操作！",score:0}],effect:"fire",tip:"山火逼近时：关门窗、关燃气、准备湿毛巾和应急包！"},{id:"wf_03",title:"火海逃生",setting:"🏃 逃生路上",icon:"🔥",desc:"山火突然改变了方向，包围了你所在的区域！火焰就在周围燃烧，浓烟让你几乎无法呼吸，你的眼睛刺痛流泪。",choices:[{text:"趴低身体，用湿衣物捂住口鼻",correct:!0,response:"✅ 正确！浓烟比火焰更致命！贴近地面空气更好，湿衣物过滤毒烟！",score:10},{text:"站起来拼命跑",correct:!1,response:"❌ 站起来会吸入更多浓烟！贴近地面的空气含氧量更高！",score:0},{text:"跳进附近的水池或水塘",correct:!1,response:"✅ 也不错！如果附近有安全的水源，浸泡在水中可以躲避火焰！",score:8}],effect:"fire",tip:"山火中的致命杀手上浓烟！贴地爬行+湿毛巾捂口鼻！"}],sandstorm:[{id:"sa_01",title:"沙暴来袭",setting:"🏜️ 沙漠",icon:"🏜️",desc:'你在沙漠中旅行，远处天边出现了一堵巨大的黄色"墙"，正在迅速逼近。风开始变大，沙粒打在身上生疼。',choices:[{text:"找岩石或沙丘背风处躲避",correct:!0,response:"✅ 正确！背风处可以躲避沙尘暴的直接冲击！",score:10},{text:"继续向前走，希望走出沙暴范围",correct:!1,response:"❌ 沙尘暴范围可能很大，能见度极低，继续走会迷路！",score:0},{text:"快跑试图甩掉沙尘暴",correct:!1,response:"❌ 人跑不过沙尘暴的！应找地方躲避等待沙暴过去！",score:0}],effect:"wind",tip:"遇沙尘暴立即找遮挡物躲避，不要试图跑赢它！"},{id:"sa_02",title:"沙暴之中",setting:"🏜️ 野外",icon:"🏜️",desc:"沙尘暴已经把你吞没，四周一片昏黄，能见度不到2米。风沙打在脸上，眼睛完全睁不开，呼吸也变得困难。",choices:[{text:"用衣物捂住口鼻和眼睛，蹲低等待沙暴过去",correct:!0,response:"✅ 正确！保护呼吸道和眼睛是沙尘暴中的首要任务！",score:10},{text:"睁大眼睛努力看清方向",correct:!1,response:"❌ 沙尘会严重伤害眼睛！必须闭上眼睛并用衣物遮挡！",score:0},{text:"大声呼救",correct:!1,response:"❌ 沙暴中张嘴呼救会让口鼻灌入沙尘！应用手势或哨子发信号！",score:5}],effect:"wind",tip:"沙暴中：护住口鼻和眼睛、蹲低不动、等沙暴过去！"}],volcanic:[{id:"vo_01",title:"火山喷发",setting:"🏔️ 火山附近",icon:"🌋",desc:"你正在参观一座火山景区，突然地面传来低沉的轰鸣声，山顶喷出巨大的烟柱和火山灰，天空瞬间变暗！",choices:[{text:"戴好头盔和护目镜，向高地撤离",correct:!0,response:"✅ 正确！火山喷发时要保护头部免受落石伤害，向高地躲避火山碎屑流！",score:10},{text:"靠近一点拍照发朋友圈",correct:!1,response:"❌ 火山喷发极其危险！火山碎屑流温度可达1000°C！马上远离！",score:0},{text:"躲进附近的山洞",correct:!1,response:"❌ 山洞可能被火山灰封堵或有有毒气体聚集！应远离火山口方向！",score:0}],effect:"fire",tip:"火山喷发：戴好护具、远离火山口、向高地撤离！"},{id:"vo_02",title:"火山灰危机",setting:"🏠 附近城镇",icon:"🌋",desc:"火山喷发后，厚厚的火山灰像雪一样落下来，压得屋顶嘎吱作响。空气中弥漫着刺鼻的硫磺味，你开始咳嗽。",choices:[{text:"戴上口罩或湿毛巾，关闭门窗，清理屋顶积灰",correct:!0,response:"✅ 正确！火山灰有毒且很重，可能压垮屋顶！戴口罩防护呼吸道！",score:10},{text:"出去拍照记录这奇观",correct:!1,response:"❌ 火山灰含有有害物质，吸入会损伤肺部！应待在室内！",score:0},{text:"打开门窗通风换气",correct:!1,response:"❌ 开窗会让更多火山灰进入室内！应紧闭门窗！",score:0}],effect:"dark",tip:"火山灰有毒！戴口罩、关门窗、及时清理屋顶积灰！"}],gas:[{id:"ga_01",title:"厨房燃气泄漏",setting:"🏠 家中厨房",icon:"💨",desc:"你在厨房做饭时突然闻到一股强烈的臭味（燃气中添加的臭味剂），灶台上的火焰已经熄灭，但燃气阀门没有关！",choices:[{text:"立即关闭燃气总阀门，轻轻打开窗户通风",correct:!0,response:"✅ 正确！关闭阀门切断气源，开窗稀释燃气浓度，是最安全的处理方式！",score:10},{text:"按下电灯开关检查泄漏位置",correct:!1,response:"❌ 极度危险！开关电器会产生电火花，可能引燃泄漏的燃气导致爆炸！",score:0},{text:"用打火机照亮查看管道",correct:!1,response:"❌ 这是最危险的行为！明火会直接引爆燃气！绝对不能这样做！",score:0}],effect:"dark",tip:"燃气泄漏：关阀门、开窗户、不要开关电器、到室外拨打燃气公司电话！"},{id:"ga_02",title:"邻居家燃气泄漏",setting:"🏢 居民楼走廊",icon:"💨",desc:"你在楼道里闻到浓重的燃气味，发现是从隔壁邻居家传出来的。敲门没人应答，情况紧急！",choices:[{text:"立即撤离楼栋，到安全处拨打燃气公司和119",correct:!0,response:"✅ 正确！不要试图自行处理，迅速撤离并通知专业人员！",score:10},{text:"尝试撬开邻居家门进入检查",correct:!1,response:"❌ 非常危险！开门会加速空气流通可能引发爆炸！应该撤离！",score:0},{text:"在楼道里大声呼喊让邻居开门",correct:!1,response:"❌ 逗留在泄漏区域很危险！应立即撤离到安全地带！",score:0}],effect:"dark",tip:"发现他人燃气泄漏：不要进入泄漏区域，立即撤离并报警！"}],elevator:[{id:"el_01",title:"电梯突然停运",setting:"🏢 高层写字楼",icon:"🛗",desc:"你正在乘坐电梯下楼，突然电梯猛地一震停了下来，灯光闪烁后恢复正常。你被困在了20楼和19楼之间！",choices:[{text:"保持冷静，按下紧急呼叫按钮，拨打电梯内标注的救援电话",correct:!0,response:"✅ 正确！保持冷静是第一位的，使用紧急呼叫装置等待专业救援！",score:10},{text:"尝试扒开电梯门爬出去",correct:!1,response:"❌ 极度危险！电梯可能随时移动，扒门可能卡在电梯井中！",score:0},{text:"从天花板检修口爬出",correct:!1,response:"❌ 非常危险！电梯井内有各种设备和线缆，可能触电或坠落！",score:0}],effect:"dark",tip:"电梯故障：保持冷静、按紧急按钮、等待救援、不要扒门！"},{id:"el_02",title:"电梯急速下坠",setting:"🏢 住宅楼",icon:"🛗",desc:"你乘坐电梯时，电梯突然开始急速下坠！你感到强烈的失重感，电梯内的人开始尖叫！",choices:[{text:"按下所有楼层按钮，背靠墙壁半蹲，双手抱头保护颈部",correct:!0,response:"✅ 正确！按所有按钮可能触发紧急制动，半蹲姿势可以缓冲冲击力！",score:10},{text:"跳起来试图减轻落地冲击",correct:!1,response:"❌ 跳跃完全无效！你和电梯的速度差会导致更严重的伤害！",score:0},{text:"躺平在地上",correct:!1,response:"❌ 躺平虽然分散了冲击力，但头部和颈部没有保护！应该背靠墙壁半蹲！",score:0}],effect:"dark",tip:"电梯下坠：按所有楼层按钮、背靠墙壁半蹲、双手抱头！"}]};function flattenScenarios(){const list=[];return["flood","typhoon","earthquake","landslide","tsunami","lightning","snowstorm","wildfire","sandstorm","volcanic","gas","elevator"].forEach(dis=>{SCENARIOS[dis]&&SCENARIOS[dis].forEach(sc=>{sc.disaster=dis,list.push(sc)})}),list}SCENARIOS.school_earthquake=[{id:"se_01",title:"校园地震",setting:"🏫 教室",icon:"🏫",disaster:"earthquake",difficulty:"medium",steps:[{text:"上课时突然发生地震，课桌剧烈晃动！",options:[{text:"立即蹲到课桌下，用书包护住头部",correct:!0,result:"你迅速躲在坚固的课桌下，用书包护住头部，避免被坠落物砸伤。",points:40},{text:"冲出教室",correct:!1,result:"地震时跑动容易被坠落物砸中，而且楼梯可能已经变形。",points:5},{text:"站在窗边",correct:!1,result:"窗户玻璃可能破碎飞溅，非常危险！",points:0}]},{text:"晃动停止了，但教学楼出现了裂缝。",options:[{text:"在老师指挥下有序撤离到操场",correct:!0,result:"你跟随老师有序撤离到开阔的操场，远离建筑物。",points:50},{text:"赶紧收拾书包再走",correct:!1,result:"余震随时可能到来，应该立即撤离，不要贪恋财物。",points:10},{text:"从窗户跳出去",correct:!1,result:"二楼以上跳窗非常危险，应该走楼梯有序撤离。",points:0}]}]}],SCENARIOS.mall_fire=[{id:"mf_01",title:"商场火警",setting:"🏬 商场",icon:"🏬",disaster:"fire",difficulty:"medium",steps:[{text:"你在商场购物，突然闻到烟味，看到天花板冒出浓烟！",options:[{text:"立即放下购物袋，寻找最近的安全出口",correct:!0,result:"你放下所有物品，迅速向安全出口移动，保持冷静。",points:40},{text:"继续购物",correct:!1,result:"火灾发生时每一秒都很宝贵，不能浪费时间。",points:0},{text:"乘坐电梯下楼",correct:!1,result:"火灾时绝对不能使用电梯！电梯可能断电把你困住。",points:0}]},{text:"安全出口的门很烫，但能推开。浓烟越来越浓。",options:[{text:"蹲低身体，用湿衣服捂住口鼻，快速通过",correct:!0,result:"你蹲低身体避开浓烟，快速通过安全门，成功逃出商场！",points:50},{text:"推门冲过去",correct:!1,result:"浓烟有毒，应该蹲低并捂住口鼻，减少吸入有害气体。",points:15},{text:"回去找其他出口",correct:!1,result:"回头更危险，应该在确保安全的情况下通过现有出口。",points:5}]}]}],SCENARIOS.subway_earthquake=[{id:"sub_01",title:"地铁地震",setting:"🚇 地铁",icon:"🚇",disaster:"earthquake",difficulty:"hard",steps:[{text:"你在地铁上，列车突然剧烈晃动！广播响起地震警报。",options:[{text:"抓紧扶手，蹲下保护头部",correct:!0,result:"你抓紧扶手稳住身体，蹲下护住头部，等待列车停稳。",points:40},{text:"尝试打开车门",correct:!1,result:"列车行驶中不能随意打开车门，而且隧道内可能有危险。",points:0},{text:"跑到车厢连接处",correct:!1,result:"车厢连接处结构较弱，晃动时反而更危险。",points:5}]},{text:"列车停了，但隧道内一片漆黑。车门打不开。",options:[{text:"等待工作人员引导疏散",correct:!0,result:"你耐心等待，地铁工作人员很快打开了应急门，引导乘客安全撤离。",points:50},{text:"砸碎车窗跳出去",correct:!1,result:"隧道内情况不明，贸然跳车可能触电或被其他列车撞到。",points:0},{text:"拨打119求助",correct:!1,result:"拨打急救电话是好的，但更应该先等待工作人员引导。",points:15}]}]}],SCENARIOS.ktv_fire=[{id:"kf_01",title:"KTV火灾",setting:"🎤 KTV包间",icon:"🎤",disaster:"fire",difficulty:"hard",steps:[{text:"你在KTV唱歌，突然门外传来尖叫，烟雾从门缝渗入！",options:[{text:"用手背触摸门把手，判断门外温度",correct:!0,result:"你用手背小心触摸门把手，发现门把手不烫，可以安全开门。",points:40},{text:"直接开门冲出去",correct:!1,result:"如果门外火势很大，直接开门会让氧气涌入，导致爆燃。",points:5},{text:"躲在包间角落",correct:!1,result:"KTV包间空间小，浓烟会很快充满整个房间。",points:0}]},{text:"走廊里烟雾弥漫，但能看到安全出口的绿色标志。",options:[{text:"弯腰捂鼻，沿墙壁快速找到安全出口",correct:!0,result:"你弯腰避开浓烟，沿墙壁找到了安全出口，成功逃出！",points:50},{text:"站着快速跑过去",correct:!1,result:"走廊上方浓烟最浓，弯腰可以呼吸到相对清洁的空气。",points:15},{text:"用手机照明",correct:!1,result:"手机照明在浓烟中作用有限，应该沿墙壁移动。",points:10}]}]}],SCENARIOS.factory_fire=[{id:"faf_01",title:"工厂火灾",setting:"🏭 工厂",icon:"🏭",disaster:"fire",difficulty:"hard",steps:[{text:"工厂车间突然起火，火势迅速蔓延！你正在操作机器。",options:[{text:"关闭机器和电源总闸，然后撤离",correct:!0,result:"你关闭了机器和电源，防止二次事故，然后迅速撤离。",points:40},{text:"立即丢下工作跑出去",correct:!1,result:"带电的机器和可燃物可能引发更大火灾，应该先关闭设备。",points:10},{text:"尝试用水灭火",correct:!1,result:"工厂可能有电气设备，用水灭火可能触电，应该先断电。",points:0}]},{text:"你跑到出口发现门被锁了，烟雾越来越浓。",options:[{text:"用灭火器砸碎旁边的玻璃逃生窗",correct:!0,result:"你用灭火器砸碎了应急逃生窗，成功逃出工厂！",points:50},{text:"退回车间找其他出路",correct:!1,result:"退回火场更加危险，应该寻找最近的逃生通道。",points:5},{text:"大声呼救等待别人来开门",correct:!1,result:"浓烟中大声呼救会吸入更多有毒气体，应该积极寻找出路。",points:10}]}]}],SCENARIOS.fishing_typhoon=[{id:"ft_01",title:"渔船避风",setting:"⛵ 海上",icon:"⛵",disaster:"typhoon",difficulty:"hard",steps:[{text:"你在渔船上作业，收到台风预警。海面开始起浪。",options:[{text:"立即收起渔具，全速驶向最近港口",correct:!0,result:"你全速返航，赶在台风到来前到达港口。",points:40},{text:"继续作业，等雨大了再走",correct:!1,result:"台风来得很快，拖延时间可能被困在海上。",points:0},{text:"原地抛锚等待",correct:!1,result:"渔船抗风能力有限，应该尽快靠岸。",points:5}]},{text:"航行途中风力骤增，巨浪不断，能见度极低。",options:[{text:"打开航行灯，全速前进",correct:!0,result:"你保持航向全速前进，最终安全抵达港口，所有船员平安！",points:50},{text:"减速慢行",correct:!1,result:"减速会增加在海上暴露的时间，应该全速前进。",points:10},{text:"下锚停船",correct:!1,result:"在台风中下锚非常危险，船只可能失控。",points:0}]}]}],SCENARIOS.mountain_flood=[{id:"mf2_01",title:"山区洪水",setting:"⛰️ 山区",icon:"⛰️",disaster:"flood",difficulty:"medium",steps:[{text:"你在山区露营，深夜听到轰隆隆的水声，河水暴涨！",options:[{text:"立即收拾帐篷，向高处转移",correct:!0,result:"你迅速转移到高处，避开了暴涨的山洪。",points:40},{text:"用沙袋堵住帐篷入口",correct:!1,result:"山洪力量巨大，沙袋根本无法阻挡。",points:0},{text:"继续睡觉",correct:!1,result:"山洪可能瞬间冲走营地，必须立即撤离！",points:0}]},{text:"你转移到高处，但发现下游有人被困在洪水中。",options:[{text:"大声呼喊指引他们往高处转移",correct:!0,result:"你指引他们找到了安全的高处，所有人成功获救。",points:50},{text:"下水去救人",correct:!1,result:"山洪流速极快，下水救人非常危险，可能被冲走。",points:0},{text:"打电话报警",correct:!1,result:"报警是对的，但同时应该先想办法指引被困者自救。",points:20}]}]}],SCENARIOS.highrise_typhoon=[{id:"ht_01",title:"高层撤离",setting:"🏢 高层公寓",icon:"🏢",disaster:"typhoon",difficulty:"medium",steps:[{text:"15级台风即将登陆，你住在20楼。窗户开始剧烈震动。",options:[{text:"用胶带贴住玻璃，拉上窗帘",correct:!0,result:"你用胶带加固了玻璃，拉上窗帘防止碎片飞溅。",points:40},{text:"跑到阳台观察风势",correct:!1,result:"阳台在台风中非常危险，可能被大风吹落物体击中。",points:0},{text:"打开窗户释放气压",correct:!1,result:"这是谣言！打开窗户会让狂风灌入，更加危险。",points:0}]},{text:"风力越来越大，玻璃出现裂痕，你很害怕。",options:[{text:"退到远离窗户的内室，用枕头护住头部",correct:!0,result:"你退到安全的内室等待台风过去，玻璃碎裂时你完全安全。",points:50},{text:"用身体挡住窗户",correct:!1,result:"玻璃碎裂可能造成严重割伤，绝不能用身体挡。",points:0},{text:"尝试逃离大楼",correct:!1,result:"台风中外出更加危险，应该留在室内安全区域。",points:5}]}]}],SCENARIOS.volcano_warning=[{id:"vw_01",title:"火山预警",setting:"🌋 火山附近",icon:"🌋",disaster:"wildfire",difficulty:"hard",steps:[{text:"你住在火山附近，政府发布火山喷发预警。地面开始震动。",options:[{text:"按政府指示立即撤离到指定避难所",correct:!0,result:"你迅速撤离到20公里外的避难所，安全了。",points:40},{text:"收拾好所有行李再走",correct:!1,result:"火山喷发速度极快，携带贵重物品会耽误宝贵的撤离时间。",points:5},{text:"跑到火山口看",correct:!1,result:"火山口附近有致命的火山灰和有毒气体，绝对不能靠近！",points:0}]},{text:"撤离途中，火山开始喷发，天空被火山灰遮蔽。",options:[{text:"戴上口罩，继续向避难所前进",correct:!0,result:"你用湿布捂住口鼻，成功到达避难所。",points:50},{text:"躲在路边等待火山灰过去",correct:!1,result:"火山灰会持续堆积，可能导致建筑坍塌，应该继续移动。",points:10},{text:"用手挡住口鼻",correct:!1,result:"火山灰颗粒极细，用手挡不住，需要专业防护口罩。",points:5}]}]}],SCENARIOS.nuclear_radiation=[{id:"nuc_01",title:"核泄漏",setting:"☢️ 核电站附近",icon:"☢️",disaster:"wildfire",difficulty:"hard",steps:[{text:"你住在核电站附近，警报响起，可能发生核泄漏！",options:[{text:"立即进入室内，关闭门窗和通风系统",correct:!0,result:"你迅速进入室内并关闭所有通风口，减少了辐射暴露。",points:40},{text:"跑到户外看情况",correct:!1,result:"户外辐射最强，应该立即进入室内。",points:0},{text:"服用碘片",correct:!1,result:"碘片需要在官方指导下服用，不能盲目自行服用。",points:20}]},{text:"广播通知居民不要外出，等待进一步指示。你在室内。",options:[{text:"打开收音机听官方广播，准备应急物资",correct:!0,result:"你通过广播了解了最新情况，做好了应急准备，成功度过危机。",points:50},{text:"打开窗户通风",correct:!1,result:"核泄漏时绝对不能开窗通风，放射性物质会进入室内。",points:0},{text:"开车逃离",correct:!1,result:"道路上可能拥堵，而且汽车不能完全阻挡辐射。",points:5}]}]}],SCENARIOS.sandstorm_highway=[{id:"sh_01",title:"高速沙尘暴",setting:"🛣️ 高速公路",icon:"🛣️",disaster:"sandstorm",difficulty:"medium",steps:[{text:"你在高速公路上开车，前方突然出现黄色沙墙！能见度骤降到几乎为零。",options:[{text:"立即打开双闪，减速驶向最近的服务区",correct:!0,result:"你安全驶入服务区，等待沙尘暴过去。",points:40},{text:"加速冲过去",correct:!1,result:"能见度极低时加速非常危险，可能撞上其他车辆或护栏。",points:0},{text:"停在路中间",correct:!1,result:"停在路中间可能被后方车辆追尾，应该靠边停车。",points:10}]},{text:"在服务区等了1小时，沙尘暴还没过去。你的车开始缺油。",options:[{text:"留在服务区内，补充食物和水，等待天气好转",correct:!0,result:"你耐心等待，沙尘暴终于过去，安全返程。",points:50},{text:"冒险上路",correct:!1,result:"沙尘暴中上路非常危险，应该耐心等待。",points:5},{text:"在车里睡觉",correct:!1,result:"应该保持警觉，关注天气变化和官方信息。",points:15}]}]}],SCENARIOS.extreme_heat=[{id:"eh_01",title:"极端高温",setting:"🌡️ 户外",icon:"🌡️",disaster:"wildfire",difficulty:"easy",steps:[{text:"气温达到42°C，你在户外工作。感到头晕、恶心。",options:[{text:"立即到阴凉处休息，补充水分",correct:!0,result:"你到阴凉处休息并大量饮水，中暑症状逐渐缓解。",points:40},{text:"继续工作",correct:!1,result:"中暑不及时处理可能发展为热射病，危及生命。",points:0},{text:"喝冰可乐降温",correct:!1,result:"冰饮料会刺激肠胃，应该喝常温水或淡盐水。",points:15}]},{text:"你的同事突然倒地，意识模糊，皮肤发红发烫。",options:[{text:"立即拨打120，同时用湿毛巾给他降温",correct:!0,result:"你紧急施救，用湿毛巾降温并等待救护车。同事脱离了危险。",points:50},{text:"给他喝冰水",correct:!1,result:"热射病患者不能喝冰水，应该用物理方法降温。",points:10},{text:"让他继续工作",correct:!1,result:"这是严重的热射病，必须立即急救！",points:0}]}]}],SCENARIOS.urban_flood=[{id:"uf_01",title:"城市内涝",setting:"🏙️ 城市街道",icon:"🏙️",disaster:"flood",difficulty:"medium",steps:[{text:"暴雨导致城市内涝，街道积水齐腰。你在路上行走。",options:[{text:"沿着地势高的路边行走，避开积水深处",correct:!0,result:"你沿着高处行走，安全到达目的地。",points:40},{text:"趟过积水",correct:!1,result:"积水下可能有打开的井盖、坑洞，非常危险。",points:5},{text:"站在电线杆旁",correct:!1,result:"积水中的电线杆可能漏电，远离电力设施！",points:0}]},{text:"水越涨越高，你被困在一辆车顶上。",options:[{text:"站在车顶上等待救援，拨打110报告位置",correct:!0,result:"你站在车顶等待，救援人员很快赶到，你安全获救。",points:50},{text:"跳入水中游走",correct:!1,result:"水流可能很急，跳入水中非常危险。",points:0},{text:"打开车门躲进车内",correct:!1,result:"水位上涨可能淹没车辆，车内会变成致命陷阱。",points:0}]}]}],SCENARIOS.forest_fire=[{id:"ff_01",title:"森林火灾",setting:"🌲 森林",icon:"🌲",disaster:"wildfire",difficulty:"hard",steps:[{text:"你在森林中徒步，突然闻到烟味，远处有火光！",options:[{text:"判断风向，向逆风方向和河流方向撤离",correct:!0,result:"你判断了风向，逆风跑向河流，成功脱离危险。",points:40},{text:"爬上高处观察",correct:!1,result:"高处离火源更近，而且烟雾在高处更浓。",points:0},{text:"顺着火势跑",correct:!1,result:"顺风跑永远跑不过火，应该逆风撤离。",points:0}]},{text:"火势蔓延很快，前方有一条小溪。",options:[{text:"涉水过溪，在对岸等待救援",correct:!0,result:"你渡过小溪到达安全区域，消防队随后赶到扑灭了火灾。",points:50},{text:"跳入水中",correct:!1,result:"溪水可能很深或有暗流，应该小心涉水。",points:20},{text:"在原地挖防火带",correct:!1,result:"一个人挖防火带效率太低，应该优先逃离火场。",points:5}]}]}],SCENARIOS.snowstorm_lost=[{id:"ssl_01",title:"暴风雪迷路",setting:"🏔️ 雪山",icon:"🏔️",disaster:"snowstorm",difficulty:"hard",steps:[{text:"你在雪山徒步时遭遇暴风雪，完全看不到路了。",options:[{text:"就地搭建临时庇护所，保存体力",correct:!0,result:"你用树枝和雪搭建了简易庇护所，保存了体力。",points:40},{text:"继续往前走",correct:!1,result:"暴风雪中盲目行走可能迷路更远或跌落悬崖。",points:0},{text:"大声呼救",correct:!1,result:"暴风雪中呼救声音传不出去，应该先保存体力。",points:10}]},{text:"暴风雪持续了一夜，你的食物快吃完了。远处似乎有灯光。",options:[{text:"朝着灯光方向小心前进，注意脚下",correct:!0,result:"你小心地向灯光走去，找到了一个护林站，安全获救！",points:50},{text:"原地等待",correct:!1,result:"有明确的求救目标时应该主动行动，而不是被动等待。",points:15},{text:"挖雪洞躲避",correct:!1,result:"发现灯光说明附近有人，应该尝试前往。",points:10}]}]}],SCENARIOS.desert_lost=[{id:"dl_01",title:"沙漠迷途",setting:"🏜️ 沙漠",icon:"🏜️",disaster:"sandstorm",difficulty:"hard",steps:[{text:"你在沙漠中迷路了，水只够喝半天的。太阳很毒。",options:[{text:"找阴凉处等待，用衣物遮挡阳光",correct:!0,result:"你保存了体力和水分，在阴凉处等待救援。",points:40},{text:"继续赶路找出口",correct:!1,result:"烈日下赶路会大量消耗水分和体力，加速脱水。",points:5},{text:"喝光所有水",correct:!1,result:"水是最宝贵的资源，应该少量多次饮用。",points:0}]},{text:"你听到远处有直升机的声音，但不确定它能否看到你。",options:[{text:"用镜子或手机屏幕反射阳光向直升机发信号",correct:!0,result:"你用反光成功引起直升机注意，被成功救援！",points:50},{text:"挥舞衣服",correct:!1,result:"从高空看挥舞衣服很难被发现，反光信号更有效。",points:20},{text:"点燃篝火",correct:!1,result:"沙漠中生火有风险，而且白天火光不明显。",points:10}]}]}],SCENARIOS.earthquake_aftershock=[{id:"eas_01",title:"地震余震",setting:"🏠 家中",icon:"🏠",disaster:"earthquake",difficulty:"medium",steps:[{text:"大地震后你回到家中，正在清理损坏的物品。突然地面再次晃动——余震来了！",options:[{text:"立即蹲在坚固的桌子下面",correct:!0,result:"你迅速躲到桌下，余震很快过去，你安全无恙。",points:40},{text:"冲出家门",correct:!1,result:"余震通常比主震弱，而且跑动中更容易被坠落物砸伤。",points:10},{text:"检查家中财物",correct:!1,result:"余震时应该先保护自身安全，不是检查财物。",points:0}]},{text:"余震后你发现墙上出现了更大的裂缝，水管也漏了。",options:[{text:"关闭水阀和电闸，检查是否有燃气泄漏",correct:!0,result:"你关闭了水阀和电闸，没有发现燃气泄漏，避免了二次灾害。",points:50},{text:"用桶接漏水",correct:!1,result:"应该先关闭水阀切断水源，不只是接水。",points:15},{text:"继续住在家里",correct:!1,result:"裂缝扩大说明房屋结构受损，应该先撤离到安全地方。",points:0}]}]}],SCENARIOS.earthquake_fire=[{id:"ef_01",title:"震后火灾",setting:"🏚️ 震后街道",icon:"🏚️",disaster:"earthquake",difficulty:"hard",steps:[{text:"地震过后，你发现邻居家燃气管道断裂，引发火灾！",options:[{text:"远离火场，拨打119报警",correct:!0,result:"你远离了火场并及时报警，消防队很快赶到灭火。",points:40},{text:"尝试用灭火器灭火",correct:!1,result:"燃气泄漏引发的火灾应该由专业人员处理。",points:10},{text:"关闭邻居家的燃气阀门",correct:!1,result:"管道已经断裂，关闭阀门可能无法阻止泄漏，还很危险。",points:5}]},{text:"火势蔓延到你的楼下了，烟雾从楼道涌入。",options:[{text:"用湿毛巾捂住口鼻，从安全楼梯向下撤离",correct:!0,result:"你弯腰捂鼻从楼梯撤离到安全地带，成功逃生！",points:50},{text:"跳窗逃生",correct:!1,result:"楼下的火不一定能威胁到你，跳窗反而更危险。",points:0},{text:"跑到楼顶等待",correct:!1,result:"烟雾向上蔓延，楼顶不是安全的地方。",points:5}]}]}];const ALL_SCENARIOS=flattenScenarios();
