const BGTheme={_themes:["deep-space","starry-night","aurora-flow","dawn-light","digital-matrix","warm-light"],_current:"deep-space",_matrixInterval:null,init(){const saved=localStorage.getItem("bg_theme");saved&&this._themes.includes(saved)&&(this._current=saved),this.apply(this._current);const names={"deep-space":"深空指挥官","starry-night":"星空极夜","aurora-flow":"极光流动","dawn-light":"自然晨曦","digital-matrix":"数字矩阵","warm-light":"温馨暖光"},nameEl=document.getElementById("currentThemeName"),descEl=document.getElementById("currentThemeDesc");nameEl&&(nameEl.textContent={"deep-space":"🌌","starry-night":"⭐","aurora-flow":"🌈","dawn-light":"🌅","digital-matrix":"💻","warm-light":"☀️"}[this._current]+" "+names[this._current]),descEl&&(descEl.textContent="当前主题："+names[this._current]),console.log("🎨 背景主题系统已启动："+this._current)},switch(theme){if(!this._themes.includes(theme))return;this._current=theme;try{localStorage.setItem("bg_theme",theme)}catch(e){console.error("Storage error:",e)}this.apply(theme);const names={"deep-space":"深空指挥官","starry-night":"星空极夜","aurora-flow":"极光流动","dawn-light":"自然晨曦","digital-matrix":"数字矩阵","warm-light":"温馨暖光"};"undefined"!=typeof V10Toast&&V10Toast.show("已切换主题："+names[theme],"success",2e3);const nameEl=document.getElementById("currentThemeName"),descEl=document.getElementById("currentThemeDesc");nameEl&&(nameEl.textContent={"deep-space":"🌌","starry-night":"⭐","aurora-flow":"🌈","dawn-light":"🌅","digital-matrix":"💻","warm-light":"☀️"}[theme]+" "+names[theme]),descEl&&(descEl.textContent="当前主题："+names[theme])},apply(theme){const body=document.body;this._themes.forEach(t=>body.classList.remove("theme-"+t)),body.classList.add("theme-"+theme),this._matrixInterval&&(clearInterval(this._matrixInterval),this._matrixInterval=null);const matrixContainer=document.getElementById("bgMatrix");matrixContainer&&(matrixContainer.innerHTML=""),"digital-matrix"===theme&&this._startMatrixRain()},_startMatrixRain(){const container=document.getElementById("bgMatrix");if(!container)return;const cols=Math.floor(window.innerWidth/20);for(let i=0;i<cols;i++){const col=document.createElement("div");col.className="matrix-col",col.style.left=20*i+"px",col.style.animationDuration=4+8*Math.random()+"s",col.style.animationDelay=5*Math.random()+"s";let text="";for(let j=0;j<30;j++)text+="01アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン"[Math.floor(48*Math.random())]+"\n";col.textContent=text,container.appendChild(col)}},getCurrent(){return this._current},next(){const idx=this._themes.indexOf(this._current),next=this._themes[(idx+1)%this._themes.length];this.switch(next)}};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",()=>BGTheme.init()):BGTheme.init(),window.BGTheme=BGTheme;
